import React, { useRef } from "react";
import {
  BarChart as RechartsBarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  Cell,
  ResponsiveContainer,
  Rectangle,
} from "recharts";
import { z } from "zod";

export const barChartPropsSchema = z.object({
  title: z.string().describe("Chart title"),
  description: z.string().describe("Brief description or subtitle"),
  data: z.array(
    z.object({
      label: z.string(),
      value: z.number(),
    }),
  ),
});

export type BarChartProps = z.infer<typeof barChartPropsSchema>;

export function BarChart({ title, description, data }: BarChartProps) {
  const CHART_COLORS = [
    "#BEC2FF",
    "#85ECCE",
    "#FFAC4D",
    "#FFF388",
    "#189370",
    "#EEE6FE",
    "#FA5F67",
  ];

  const TOOLTIP_STYLE = {
    backgroundColor: "#ffffff",
    border: "1px solid #e2e8f0",
    borderRadius: "10px",
    padding: "10px 14px",
    color: "#0f172a",
    fontSize: "13px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  };

  // Track which bars have already been rendered so only newly-arriving ones animate.
  const seen = useRef(new Set<number>());
  const isNew = (i: number) => {
    if (seen.current.has(i)) return false;
    seen.current.add(i);
    return true;
  };

  if (!data || !Array.isArray(data) || data.length === 0) {
    return (
      <div className="max-w-2xl mx-auto my-4 rounded-xl border border-slate-200 bg-white p-6">
        <div className="font-semibold text-slate-900">{title}</div>
        <div className="text-sm text-slate-500">{description}</div>
        <p className="text-slate-400 text-center py-8 text-sm">
          No data available
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto my-4 overflow-hidden rounded-xl border border-slate-200 bg-white">
      <style>{`
        @keyframes barSlideIn {
          from { transform: translateY(40px); opacity: 0; }
          20% { opacity: 1; }
          to { transform: translateY(0); opacity: 1; }
        }
      `}</style>
      <div className="p-4 pb-2">
        <div className="font-semibold text-slate-900">{title}</div>
        <div className="text-sm text-slate-500">{description}</div>
      </div>
      <div className="px-4 pb-4">
        <ResponsiveContainer width="100%" height={280}>
          <RechartsBarChart
            data={data}
            margin={{ top: 12, right: 12, bottom: 4, left: -8 }}
          >
            <CartesianGrid
              strokeDasharray="3 3"
              stroke="#e2e8f0"
              vertical={false}
            />
            <XAxis
              dataKey="label"
              tick={{ fontSize: 12, fill: "#64748b" }}
              stroke="#e2e8f0"
              tickLine={false}
              axisLine={false}
            />
            <YAxis
              tick={{ fontSize: 12, fill: "#64748b" }}
              stroke="#e2e8f0"
              tickLine={false}
              axisLine={false}
            />
            <Tooltip
              contentStyle={TOOLTIP_STYLE}
              cursor={{ fill: "#f1f5f9", opacity: 0.5 }}
            />
            <Bar
              isAnimationActive={false}
              dataKey="value"
              radius={[6, 6, 0, 0]}
              maxBarSize={48}
              shape={(props: any) => (
                <g
                  style={
                    isNew(props.index as number)
                      ? {
                          animation:
                            "barSlideIn 0.5s cubic-bezier(0.16, 1, 0.3, 1) both",
                        }
                      : undefined
                  }
                >
                  <Rectangle {...props} />
                </g>
              )}
            >
              {data.map((_, index) => (
                <Cell
                  key={index}
                  fill={CHART_COLORS[index % CHART_COLORS.length]}
                />
              ))}
            </Bar>
          </RechartsBarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

import React from "react";
import { z } from "zod";

export const pieChartPropsSchema = z.object({
  title: z.string().describe("Chart title"),
  description: z.string().describe("Brief description or subtitle"),
  data: z.array(
    z.object({
      label: z.string(),
      value: z.number(),
    }),
  ),
});

export type PieChartProps = z.infer<typeof pieChartPropsSchema>;

export function PieChart({ title, description, data }: PieChartProps) {
  const CHART_COLORS = [
    "#BEC2FF",
    "#85ECCE",
    "#FFAC4D",
    "#FFF388",
    "#189370",
    "#EEE6FE",
    "#FA5F67",
  ];

  if (!data || !Array.isArray(data) || data.length === 0) {
    return (
      <div className="max-w-lg mx-auto my-4 rounded-xl border border-slate-200 bg-white p-6">
        <div className="font-semibold text-slate-900">{title}</div>
        <div className="text-sm text-slate-500">{description}</div>
        <p className="text-slate-400 text-center py-8 text-sm">
          No data available
        </p>
      </div>
    );
  }

  const total = data.reduce((sum, d) => sum + (Number(d.value) || 0), 0);

  // Donut slice geometry
  const size = 240;
  const strokeWidth = 40;
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const center = size / 2;

  let accumulated = 0;
  const slices = data.map((item, index) => {
    const val = Number(item.value) || 0;
    const ratio = total > 0 ? val / total : 0;
    const arc = ratio * circumference;
    const startAt = accumulated;
    accumulated += arc;
    return {
      arc,
      gap: circumference - arc,
      dashoffset: -startAt,
      color: CHART_COLORS[index % CHART_COLORS.length],
    };
  });

  return (
    <div className="max-w-lg mx-auto my-4 overflow-hidden rounded-xl border border-slate-200 bg-white">
      <div className="p-4 pb-0">
        <div className="font-semibold text-slate-900">{title}</div>
        <div className="text-sm text-slate-500">{description}</div>
      </div>
      <div className="px-4 pb-4 pt-4">
        <svg
          width="100%"
          viewBox={`0 0 ${size} ${size}`}
          className="block mx-auto"
          style={{ maxWidth: size, transform: "scaleX(-1)" }}
        >
          <circle
            cx={center}
            cy={center}
            r={radius}
            fill="none"
            stroke="#f1f5f9"
            strokeWidth={strokeWidth}
          />
          {slices.map((slice, i) => (
            <circle
              key={i}
              cx={center}
              cy={center}
              r={radius}
              fill="none"
              stroke={slice.color}
              strokeWidth={strokeWidth}
              strokeDasharray={`${slice.arc} ${slice.gap}`}
              strokeDashoffset={slice.dashoffset}
              strokeLinecap="butt"
              transform={`rotate(-90 ${center} ${center})`}
            />
          ))}
        </svg>

        <div className="space-y-2 pt-4">
          {data.map((item, index) => {
            const val = Number(item.value) || 0;
            const pct = total > 0 ? ((val / total) * 100).toFixed(0) : 0;
            return (
              <div key={index} className="flex items-center gap-3 text-sm">
                <span
                  className="inline-block h-3 w-3 rounded-full shrink-0"
                  style={{
                    backgroundColor: CHART_COLORS[index % CHART_COLORS.length],
                  }}
                />
                <span className="flex-1 text-slate-900 truncate">
                  {item.label}
                </span>
                <span className="text-slate-500 tabular-nums">
                  {val.toLocaleString()}
                </span>
                <span className="text-slate-500 text-sm w-10 text-right tabular-nums">
                  {pct}%
                </span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

"use client";

import React from "react";
import {
  CopilotKit,
  CopilotChat,
  useAgent,
  UseAgentUpdate,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { InlineAgentStateCard } from "./InlineAgentStateCard";

/**
 * Agentic Generative UI — In-Chat State Rendering
 *
 * Demonstrates how to render intermediate agent state inline within the chat
 * transcript while a long-running agent task is in progress. The previous
 * v1 API `useCoAgentStateRender` has been replaced: in v2 you subscribe to
 * state updates via `useAgent({ updates: [OnStateChanged, OnRunStatusChanged] })`
 * and inject the rendered card through the `messageView.children` slot on
 * `<CopilotChat />`.
 */
export default function GenUiAgentDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="gen-ui-agent">
      <div className="flex justify-center items-center h-screen w-full">
        <div className="h-full w-full max-w-4xl">
          <Chat />
        </div>
      </div>
    </CopilotKit>
  );
}

// The agent's state shape is open-ended; we render whatever keys it emits.
type AgentState = Record<string, unknown> | undefined;

function Chat() {
  // Subscribe to state + run-status changes so the inline progress card
  // re-renders whenever the agent emits a state update or toggles isRunning.
  const { agent } = useAgent({
    agentId: "gen-ui-agent",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Run a 3-step task",
        message:
          "Run a 3-step task: fetch data, process it, then summarize the result.",
      },
      {
        title: "Plan a project",
        message: "Break this down into steps: planning a small web app launch.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as AgentState;
  const isRunning = agent.isRunning;

  const stateEntries = agentState
    ? Object.entries(agentState).filter(
        ([, v]) => v !== undefined && v !== null,
      )
    : [];

  return (
    <CopilotChat
      agentId="gen-ui-agent"
      className="h-full rounded-2xl"
      messageView={{
        children: ({ messageElements, interruptElement }) => (
          <div
            data-testid="copilot-message-list"
            className="flex flex-col gap-2"
          >
            {messageElements}
            {(isRunning || stateEntries.length > 0) && (
              <InlineAgentStateCard
                isRunning={isRunning}
                stateEntries={stateEntries}
              />
            )}
            {interruptElement}
          </div>
        ),
      }}
    />
  );
}

"use client";

import React from "react";

export function InlineAgentStateCard({
  isRunning,
  stateEntries,
}: {
  isRunning: boolean;
  stateEntries: [string, unknown][];
}) {
  return (
    <div
      data-testid="agent-state-card"
      className="my-3 mx-4 rounded-xl border border-gray-200 bg-gradient-to-br from-blue-50 via-white to-purple-50 p-4 shadow-sm"
    >
      <div className="flex items-center gap-2">
        {isRunning ? <SpinnerIcon /> : <CheckIcon />}
        <span className="text-sm font-semibold text-gray-800">
          {isRunning ? "Agent working…" : "Agent idle"}
        </span>
      </div>

      {stateEntries.length > 0 && (
        <div className="mt-3 space-y-1.5">
          {stateEntries.map(([key, value]) => (
            <div
              key={key}
              data-testid="agent-state-entry"
              className="flex items-start gap-2 text-xs"
            >
              <span className="font-medium text-gray-600">{key}:</span>
              <span className="font-mono text-gray-800 break-all">
                {formatValue(value)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value;
  if (typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  try {
    const json = JSON.stringify(value);
    return json.length > 120 ? json.slice(0, 117) + "…" : json;
  } catch {
    return String(value);
  }
}

function SpinnerIcon() {
  return (
    <svg
      className="w-4 h-4 animate-spin text-blue-600"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      />
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      />
    </svg>
  );
}

function CheckIcon() {
  return (
    <svg
      className="w-4 h-4 text-green-600"
      fill="none"
      stroke="currentColor"
      viewBox="0 0 24 24"
    >
      <path
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth={3}
        d="M5 13l4 4L19 7"
      />
    </svg>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { CopilotKit } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useAgent,
  UseAgentUpdate,
  useCopilotKit,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";

enum SkillLevel {
  BEGINNER = "Beginner",
  INTERMEDIATE = "Intermediate",
  ADVANCED = "Advanced",
}

enum CookingTime {
  FiveMin = "5 min",
  FifteenMin = "15 min",
  ThirtyMin = "30 min",
  FortyFiveMin = "45 min",
  SixtyPlusMin = "60+ min",
}

const cookingTimeValues = [
  { label: CookingTime.FiveMin, value: 0 },
  { label: CookingTime.FifteenMin, value: 1 },
  { label: CookingTime.ThirtyMin, value: 2 },
  { label: CookingTime.FortyFiveMin, value: 3 },
  { label: CookingTime.SixtyPlusMin, value: 4 },
];

enum SpecialPreferences {
  HighProtein = "High Protein",
  LowCarb = "Low Carb",
  Spicy = "Spicy",
  BudgetFriendly = "Budget-Friendly",
  OnePotMeal = "One-Pot Meal",
  Vegetarian = "Vegetarian",
  Vegan = "Vegan",
}

interface Ingredient {
  icon: string;
  name: string;
  amount: string;
}

interface RecipeData {
  title: string;
  skill_level: SkillLevel;
  cooking_time: CookingTime;
  special_preferences: string[];
  ingredients: Ingredient[];
  instructions: string[];
}

interface RecipeAgentState {
  recipe: RecipeData;
}

const INITIAL_STATE: RecipeAgentState = {
  recipe: {
    title: "Make Your Recipe",
    skill_level: SkillLevel.INTERMEDIATE,
    cooking_time: CookingTime.FortyFiveMin,
    special_preferences: [],
    ingredients: [
      { icon: "🥕", name: "Carrots", amount: "3 large, grated" },
      { icon: "🌾", name: "All-Purpose Flour", amount: "2 cups" },
    ],
    instructions: ["Preheat oven to 350\u00B0F (175\u00B0C)"],
  },
};

export default function SharedStateReadDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="shared-state-read">
      <div className="min-h-screen w-full flex items-center justify-center">
        <Recipe />
        <CopilotSidebar
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "AI Recipe Assistant",
          }}
        />
      </div>
    </CopilotKit>
  );
}

function Recipe() {
  const { agent } = useAgent({
    agentId: "shared-state-read",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });
  const { copilotkit } = useCopilotKit();

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Create Italian recipe",
        message: "Create a delicious Italian pasta recipe.",
      },
      {
        title: "Make it healthier",
        message: "Make the recipe healthier with more vegetables.",
      },
      {
        title: "Suggest variations",
        message: "Suggest some creative variations of this recipe.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as RecipeAgentState | undefined;
  const setAgentState = (s: RecipeAgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  useEffect(() => {
    if (!agentState?.recipe) {
      setAgentState(INITIAL_STATE);
    }
  }, []);

  const [recipe, setRecipe] = useState(INITIAL_STATE.recipe);
  const [editingInstructionIndex, setEditingInstructionIndex] = useState<
    number | null
  >(null);
  const changedKeysRef = useRef<string[]>([]);

  const updateRecipe = (partialRecipe: Partial<RecipeData>) => {
    setAgentState({
      ...(agentState || INITIAL_STATE),
      recipe: {
        ...recipe,
        ...partialRecipe,
      },
    });
    setRecipe({
      ...recipe,
      ...partialRecipe,
    });
  };

  // Sync agent state changes into local recipe state
  const newRecipeState = { ...recipe };
  const newChangedKeys: string[] = [];

  for (const key in recipe) {
    if (
      agentState?.recipe &&
      (agentState.recipe as any)[key] !== undefined &&
      (agentState.recipe as any)[key] !== null
    ) {
      let agentValue = (agentState.recipe as any)[key];
      const recipeValue = (recipe as any)[key];

      if (typeof agentValue === "string") {
        agentValue = agentValue.replace(/\\n/g, "\n");
      }

      if (JSON.stringify(agentValue) !== JSON.stringify(recipeValue)) {
        (newRecipeState as any)[key] = agentValue;
        newChangedKeys.push(key);
      }
    }
  }

  if (newChangedKeys.length > 0) {
    changedKeysRef.current = newChangedKeys;
  } else if (!isLoading) {
    changedKeysRef.current = [];
  }

  useEffect(() => {
    setRecipe(newRecipeState);
  }, [JSON.stringify(newRecipeState)]);

  const handleTitleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    updateRecipe({ title: event.target.value });
  };

  const handleSkillLevelChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({ skill_level: event.target.value as SkillLevel });
  };

  const handleDietaryChange = (preference: string, checked: boolean) => {
    if (checked) {
      updateRecipe({
        special_preferences: [...recipe.special_preferences, preference],
      });
    } else {
      updateRecipe({
        special_preferences: recipe.special_preferences.filter(
          (p) => p !== preference,
        ),
      });
    }
  };

  const handleCookingTimeChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({
      cooking_time: cookingTimeValues[Number(event.target.value)].label,
    });
  };

  const addIngredient = () => {
    updateRecipe({
      ingredients: [
        ...recipe.ingredients,
        { icon: "🍴", name: "", amount: "" },
      ],
    });
  };

  const updateIngredient = (
    index: number,
    field: keyof Ingredient,
    value: string,
  ) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients[index] = {
      ...updatedIngredients[index],
      [field]: value,
    };
    updateRecipe({ ingredients: updatedIngredients });
  };

  const removeIngredient = (index: number) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients.splice(index, 1);
    updateRecipe({ ingredients: updatedIngredients });
  };

  const addInstruction = () => {
    const newIndex = recipe.instructions.length;
    updateRecipe({ instructions: [...recipe.instructions, ""] });
    setEditingInstructionIndex(newIndex);
  };

  const updateInstruction = (index: number, value: string) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions[index] = value;
    updateRecipe({ instructions: updatedInstructions });
  };

  const removeInstruction = (index: number) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions.splice(index, 1);
    updateRecipe({ instructions: updatedInstructions });
  };

  return (
    <form
      data-testid="recipe-card"
      className="max-w-2xl mx-auto p-6 bg-white rounded-2xl shadow-lg border border-gray-100"
    >
      {/* Recipe Title */}
      <div className="mb-6">
        <input
          type="text"
          value={recipe.title || ""}
          onChange={handleTitleChange}
          className="text-3xl font-bold w-full border-none outline-none bg-transparent"
        />

        <div className="flex gap-4 mt-3">
          <div className="flex items-center gap-1">
            <span>🕒</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={
                cookingTimeValues.find((t) => t.label === recipe.cooking_time)
                  ?.value || 3
              }
              onChange={handleCookingTimeChange}
            >
              {cookingTimeValues.map((time) => (
                <option key={time.value} value={time.value}>
                  {time.label}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-1">
            <span>🏆</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={recipe.skill_level}
              onChange={handleSkillLevelChange}
            >
              {Object.values(SkillLevel).map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Dietary Preferences */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("special_preferences") && <Ping />}
        <h2 className="text-lg font-semibold mb-2">Dietary Preferences</h2>
        <div className="flex flex-wrap gap-2">
          {Object.values(SpecialPreferences).map((option) => (
            <label
              key={option}
              className="flex items-center gap-1 text-sm bg-gray-50 px-3 py-1.5 rounded-full cursor-pointer hover:bg-gray-100"
            >
              <input
                type="checkbox"
                checked={recipe.special_preferences.includes(option)}
                onChange={(e) => handleDietaryChange(option, e.target.checked)}
              />
              <span>{option}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Ingredients */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("ingredients") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Ingredients</h2>
          <button
            data-testid="add-ingredient-button"
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addIngredient}
          >
            + Add Ingredient
          </button>
        </div>
        <div data-testid="ingredients-container" className="space-y-2">
          {recipe.ingredients.map((ingredient, index) => (
            <div
              key={index}
              data-testid="ingredient-card"
              className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg"
            >
              <div className="text-2xl">{ingredient.icon || "🍴"}</div>
              <div className="flex-1 flex gap-2">
                <input
                  type="text"
                  value={ingredient.name || ""}
                  onChange={(e) =>
                    updateIngredient(index, "name", e.target.value)
                  }
                  placeholder="Ingredient name"
                  className="flex-1 text-sm border rounded px-2 py-1"
                />
                <input
                  type="text"
                  value={ingredient.amount || ""}
                  onChange={(e) =>
                    updateIngredient(index, "amount", e.target.value)
                  }
                  placeholder="Amount"
                  className="w-32 text-sm border rounded px-2 py-1"
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl"
                onClick={() => removeIngredient(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("instructions") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Instructions</h2>
          <button
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addInstruction}
          >
            + Add Step
          </button>
        </div>
        <div data-testid="instructions-container" className="space-y-3">
          {recipe.instructions.map((instruction, index) => (
            <div key={index} className="flex items-start gap-3">
              <div className="flex-shrink-0 w-7 h-7 rounded-full bg-blue-500 text-white flex items-center justify-center text-sm font-bold">
                {index + 1}
              </div>
              <div
                className="flex-1 relative"
                onClick={() => setEditingInstructionIndex(index)}
              >
                <textarea
                  className="w-full text-sm border rounded px-3 py-2 resize-none"
                  value={instruction || ""}
                  onChange={(e) => updateInstruction(index, e.target.value)}
                  placeholder="Enter cooking instruction..."
                  onFocus={() => setEditingInstructionIndex(index)}
                  onBlur={() => setEditingInstructionIndex(null)}
                  rows={2}
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl mt-1"
                onClick={() => removeInstruction(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Improve with AI Button */}
      <div className="flex justify-center">
        <button
          data-testid="improve-button"
          className={`px-6 py-3 rounded-xl font-semibold text-white transition-all ${
            isLoading
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-gradient-to-r from-blue-500 to-purple-500 hover:from-blue-600 hover:to-purple-600 shadow-lg"
          }`}
          type="button"
          onClick={() => {
            if (!isLoading) {
              agent.addMessage({
                id: crypto.randomUUID(),
                role: "user",
                content: "Improve the recipe",
              });
              copilotkit.runAgent({ agent });
            }
          }}
          disabled={isLoading}
        >
          {isLoading ? "Please Wait..." : "Improve with AI"}
        </button>
      </div>
    </form>
  );
}

function Ping() {
  return (
    <span className="absolute -top-1 -right-1 flex h-3 w-3">
      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
      <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500" />
    </span>
  );
}

