import React, { useRef } from "react";

/**
 * Composer for the headless chat.
 *
 * A textarea plus a Send / Stop toggle. Enter submits; Shift+Enter inserts a
 * newline. The textarea is disabled while the agent is running so users can't
 * pile up concurrent turns.
 */
export function InputBar({
  value,
  onChange,
  onSubmit,
  onStop,
  isRunning,
  canStop,
}: {
  value: string;
  onChange: (v: string) => void;
  onSubmit: () => void;
  onStop: () => void;
  isRunning: boolean;
  canStop: boolean;
}) {
  const inputRef = useRef<HTMLTextAreaElement>(null);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      onSubmit();
    }
  };

  return (
    <form
      className="border-t border-gray-200 p-3 flex gap-2 items-end"
      onSubmit={(e) => {
        e.preventDefault();
        onSubmit();
      }}
    >
      <textarea
        ref={inputRef}
        rows={1}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={isRunning ? "Agent is working..." : "Type a message..."}
        disabled={isRunning}
        className="flex-1 resize-none rounded-2xl border border-gray-300 px-4 py-2 text-sm leading-6 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100 disabled:text-gray-400"
      />
      {canStop ? (
        <button
          type="button"
          onClick={onStop}
          className="rounded-full px-4 py-2 text-sm font-medium bg-red-600 text-white hover:bg-red-700"
        >
          Stop
        </button>
      ) : (
        <button
          type="submit"
          disabled={isRunning || value.trim().length === 0}
          className="rounded-full px-4 py-2 text-sm font-medium bg-blue-600 text-white hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed"
        >
          Send
        </button>
      )}
    </form>
  );
}

"use client";

import React, { useLayoutEffect, useRef } from "react";
import type { AssistantMessage, Message, UserMessage } from "@ag-ui/core";
import { UserBubble } from "./user-bubble";
import { AssistantBubble } from "./assistant-bubble";
import { TypingIndicator } from "./typing-indicator";

/**
 * Scrollable messages area. Auto-scrolls to the bottom whenever the message
 * list grows or existing content streams in. Only user + assistant messages
 * are rendered here — tool (`role: "tool"`) messages are consumed inline by
 * the assistant bubble that produced the tool call.
 */
export function MessageList({
  messages,
  isRunning,
}: {
  messages: Message[];
  isRunning: boolean;
}) {
  const scrollRef = useRef<HTMLDivElement>(null);

  // Build a cheap fingerprint so we auto-scroll on streaming content changes
  // (not just new messages). Mirrors the approach used elsewhere in the SDK.
  const fingerprint = messages
    .map((m) => {
      const contentLen =
        typeof m.content === "string"
          ? m.content.length
          : Array.isArray(m.content)
            ? m.content.length
            : 0;
      const tcLen =
        "toolCalls" in m && Array.isArray(m.toolCalls)
          ? m.toolCalls.map((tc) => tc.function.arguments.length).join(",")
          : "";
      return `${m.id}:${contentLen}:${tcLen}`;
    })
    .join("|");

  useLayoutEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight;
  }, [fingerprint, isRunning]);

  const visible = messages.filter(
    (m) => m.role === "user" || m.role === "assistant",
  );

  return (
    <div
      ref={scrollRef}
      data-testid="headless-complete-messages"
      className="flex-1 min-h-0 overflow-y-auto px-4 py-4 space-y-3"
    >
      {visible.length === 0 && (
        <div className="text-center text-sm text-gray-400 mt-8">
          Ask for a bar chart or a pie chart to see inline tool rendering.
        </div>
      )}
      {visible.map((m) =>
        m.role === "user" ? (
          <UserBubble key={m.id} message={m as UserMessage} />
        ) : (
          <AssistantBubble
            key={m.id}
            message={m as AssistantMessage}
            allMessages={messages}
          />
        ),
      )}
      {isRunning && <TypingIndicator />}
    </div>
  );
}

